function formatTemplate(template, values) {
    return template.replace(/\{([a-zA-Z0-9_]+)\}/g, (match, key) => {
        if (Object.prototype.hasOwnProperty.call(values, key)) {
            return String(values[key]);
        }
        return match;
    });
}
function listSupportedPushLanguages() {
    return [...exports.SUPPORTED_PUSH_LANGUAGES];
}
function parseSupportedPushLanguage(value) {
    if (!value) {
        return null;
    }
    const normalized = value.trim().toLowerCase();
    if (!normalized) {
        return null;
    }
    if (!exports.SUPPORTED_PUSH_LANGUAGES.includes(normalized)) {
        return null;
    }
    return normalized;
}
function normalizeSupportedPushLanguage(value) {
    return parseSupportedPushLanguage(value) ?? exports.DEFAULT_PUSH_LANGUAGE;
}
function pushLocalizationFor(languageCode) {
    const templates = PUSH_LOCALIZATION[languageCode] ?? EN_LOCALIZATION;
    return {
        languageCode,
        localeTag: templates.localeTag,
        municipalityLabel: templates.municipalityLabel,
        heatWarningTitle: templates.heatWarningTitle,
        coldWarningTitle: templates.coldWarningTitle,
        buildHeatBody: (name, level) => formatTemplate(templates.heatBodyTemplate, { name, level }),
        buildColdBody: (name) => formatTemplate(templates.coldBodyTemplate, { name }),
        formatTodayRange: (startClock, endClock) => formatTemplate(templates.todayRangeTemplate, { start: startClock, end: endClock }),
        formatValidRange: (startText, endText) => formatTemplate(templates.validRangeTemplate, { start: startText, end: endText }),
        formatTodayFrom: (startClock) => formatTemplate(templates.todayFromTemplate, { start: startClock }),
        formatFrom: (startText) => formatTemplate(templates.fromTemplate, { start: startText }),
        formatTodayUntil: (endClock) => formatTemplate(templates.todayUntilTemplate, { end: endClock }),
        formatUntil: (endText) => formatTemplate(templates.untilTemplate, { end: endText }),
        formatTimeWindowChanged: (previousText, currentText) => formatTemplate(templates.timeWindowChangedTemplate, {
            previous: previousText,
            current: currentText,
        }),
        formatTimeWindowUpdated: (currentText) => formatTemplate(templates.timeWindowUpdatedTemplate, { current: currentText }),
        defaultTopicTestTitle: `Test: ${templates.heatWarningTitle}`,
        defaultTopicTestBody: templates.manualTestTopicBody,
        defaultTokenTestTitle: `Test: ${templates.heatWarningTitle} (Token)`,
        defaultTokenTestBody: templates.manualTestTokenBody,
    };
}
